var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"선배님들! 바로 저김다!","JPN":"先輩方！　あそこっす！","ENG":"Ma’ams! Over there!","TWN":"前輩們！就是那裡！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_ANIMAL_B"},{"id":"L3_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"호오. 사람이 많네. 무슨 이벤튼데 같이 참가하자고 난리야?","JPN":"おお、人が多いわね。どんなイベントなの？　一緒に参加したいってあんなに騒いでたけど。","ENG":"Hey, that’s a lot of people. So what’s this event you want us to participate in?","TWN":"哇喔～好多人喔。這麼熱鬧是什麼活動？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD"},{"id":"L4_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"댄스 배틀임다!","JPN":"ダンスバトルっす！","ENG":"A dance battle, ma’am!","TWN":"是舞蹈對決！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"댄스, 뭐……?","JPN":"ダンス、な、なに……！","ENG":"A dance... what?","TWN":"舞蹈什麼…？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"제가 잘못 들은 거겠죠? 댄스 배틀이라고 했나요?","JPN":"私の聞き間違いでしょうか？　ダンスバトルって言いましたか？","ENG":"Did you just say a dance battle?","TWN":"我有聽錯嗎？你是說舞蹈對決嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"댄스 배틀 맞슴다. 잘 들으셨지 말임다!","JPN":"ダンスバトルで合ってるっすよ。","ENG":"Yes, a dance battle. You heard correct, ma’am!","TWN":"是舞蹈對決沒錯，前輩沒聽錯唷！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"하아……. 실화입니까…….","JPN":"はあ……マジか、ですか……","ENG":"*Sigh* Are you for real?","TWN":"哈…認真的嗎…"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"메이드장님도 안 계신 마당에, 우리가 기죽어 있을 수는 없슴다!","JPN":"メイド長もいないし、モネたちも気合入れていかないとっす！","ENG":"We can’t stay down just because the Chief Maid is away!","TWN":"女僕長又不在，我們更不能畏戰！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"그래서 모네가 급히 플로라★러브★러브★메이드★댄스를 3인 버전으로 바꿔봤슴다~","JPN":"それで、モネが急いでフローラ★ラブ★ラブ★メイド★ダンスを3人バージョンに変えてみたっす！","ENG":"So Mone changed the Flora ★ Love ★ Love ★ Maid ★ Dance into a trio version.","TWN":"所以莫妮趕快換成芙蘿拉★LOVE★LOVE★女僕★舞三人版～"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"선배님들이라면 금방 동선 익히실 수 있을 검다~","JPN":"先輩たちならすぐダンスを覚えられると思うっす！","ENG":"I’m sure you’ll learn it easily, ma’ams.","TWN":"前輩們的話應該很快就能熟悉動作吧？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"우리가 언제 기죽어 있었다고……?","JPN":"そもそも気合入れる必要はある……？","ENG":"We were never down in the first place...","TWN":"我們什麼時候畏戰過……？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"주인님께서 하달하신 임무는 어쩌고, 저런 이벤트에나 참가하자고 하는 거죠?","JPN":"ご主人様からの任務を放棄して、あんなイベントに参加するということですか？","ENG":"What about our Master’s mission? Why should we attend this event?","TWN":"意思是要把主人下達的命令擱在一邊，參加那種活動嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"주인님 말씀대로 하는 검다! 분명 잘 놀고 오라고 하지 않으셨슴까?","JPN":"これもご主人様の意向っす！　楽しんできてと確かにおっしゃってたじゃないっすか！","ENG":"This is the mission! The Master told us to enjoy ourselves, ma’am!","TWN":"我照主人的意思唷！主人不是叫我好好玩嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"그건 맞아. 나도 그렇게 들었어.","JPN":"それはそうだけど。私もそう聞いたわ。","ENG":"She’s right. That was the instruction.","TWN":"莫妮說的沒錯，我聽到的也是那樣。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"하지만 그거랑 댄스 배틀이랑은 별로 연관 짓고 싶진 않은데.","JPN":"でも、それとダンスバトルはあまり関係ない気がするけど。","ENG":"But that doesn’t necessarily mean attending a dance battle.","TWN":"只是我不願意把舞蹈對決和主人的命令連在一起。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"그치만……","JPN":"でも……","ENG":"But...","TWN":"可是…"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"모네.","JPN":"モネ。","ENG":"Mone.","TWN":"莫妮。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"아앗. 릴리 선배님의 부드러운 말투…… 무지 불안함다……","JPN":"あっ。リリー先輩のこの優しい口調は……不安っす……","ENG":"Oh, you sound very calm... which makes me very nervous, ma’am.","TWN":"嗚嗚，莉莉前輩溫柔的語氣……讓我非常不安……"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"플로라★러브★러브★메이드★댄스를 우리 셋만 춘다면 메이드장님께서 서운해하시지 않을까요?","JPN":"フローラ★ラブ★ラブ★メイド★ダンスを私たち三人だけ踊ると、メイド長が寂しがるんじゃないでしょうか。","ENG":"The Chief Maid might feel left out if we do the Flora ★ Love ★ Love ★ Maid ★ Dance in trio version. Don’t you think?","TWN":"只有我們三個跳芙蘿拉★LOVE★LOVE★女僕★舞的話，女僕長不會難過嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"메이드장이? 별로 그럴 것 같진……","JPN":"メイド長が？　別にそうでもない気が……","ENG":"The Chief Maid? I don’t think—","TWN":"女僕長？她應該不會吧……"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"야! 왜 때려?!","JPN":"いてっ！　なんで叩くの！？","ENG":"Aw! Why did you hit me?!","TWN":"喂！幹嘛打我？！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"……아무튼 그런 상황을 막기 위해서라도, 댄스는 4인 체제를 유지했으면 좋겠어요.","JPN":"……とにかく、そんな状況を防ぐためにも、ダンスは4人体制を維持してほしいです。","ENG":"... Anyways, since I don’t want our Chief to feel that way, I would like to keep the dance as it is—the four person version.","TWN":"…不管怎樣，我們還是要考慮到女僕長，我希望那個舞可以4個人一起跳。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"그리고 메이드장님은 현재 다른 임무를 이행하고 계시니까요.","JPN":"そしてメイド長は現在他の任務を遂行中です。","ENG":"And the Chief is away on another mission at the moment, so...","TWN":"而且女僕長正在執行其他任務呢。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"제 말뜻을 이해했나요, 모네?","JPN":"今の話を理解しましたか、モネ？","ENG":"Do you understand me, Mone?","TWN":"你知道我的意思吧，莫妮？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"완벽하게 이해했슴다!","JPN":"完璧に理解したっす！","ENG":"Absolutely, ma’am!","TWN":"非常清楚！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"메이드장님을 모셔와서 플로라★러브★러브★메이드★댄스를 추자는 거 아님까?","JPN":"メイド長を連れてきてフローラ★ラブ★ラブ★メイド★ダンスを踊ろうということっすね？","ENG":"You want me to bring the Chief Maid here for the dance, am I correct?","TWN":"你的意思，是要請女僕長一起來跳芙蘿拉★LOVE★LOVE★女僕★舞對吧？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"그건 그거대로 좋네. 혼자만 놀러간 거 약올랐는데.","JPN":"それはそれでいいね。一人で遊びに行ったのもちょっとムカついてたし。","ENG":"Oh, that’s a good idea. I was envious of her going off having fun by herself.","TWN":"這樣也好。女僕長一個人去玩我有點不開心。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"놀러가다뇨. 임무 수행이라고 몇 번을 얘기했는데. 말씀 삼가시죠.","JPN":"遊びに行っただなんて。任務遂行だと何度も話したはずです。そんな発言は控えてください。","ENG":"She’s not on vacation, she’s on a mission. I told you several times.","TWN":"才不是去玩，我說過很多遍是去執行任務，請注意用詞。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"흥. 그거나 그거나.","JPN":"ふん。変わんないでしょ。","ENG":"Hmpf. Whatever.","TWN":"哼，還不是都一樣。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"웨딩 드레스까지 입었으면 결혼하는 거 아니면 놀러간 거지, 뭐.","JPN":"ウェディングドレスまで着てるのに結婚するんじゃないなら、遊びに行ったに決まってるわ。","ENG":"She was wearing a wedding dress, that means either she’s getting married or having fun.","TWN":"還穿上婚紗，不是去結婚就是去玩吧？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"그렇게 편협한 생각을 하니까 당신이 지금 이 모양인 겁니다.","JPN":"そんなに偏狭な考え方をするから、いつまでたっても成長しないわけです。","ENG":"Your narrow-mindedness will be your downfall.","TWN":"你就是想法那麼偏頗，現在才會走鐘吧。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"뭐? 너 말 다 했어?","JPN":"は？　今なんて言った？","ENG":"What did you just say?","TWN":"什麼？你說夠沒？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"아앗! 선배님들! 지금 그러고 있을 때가 아님다!","JPN":"あっ、先輩方！　揉めている場合じゃないっす！","ENG":"Ah! This is not the time for bickering, ma’ams!","TWN":"唉唷！前輩們！現在不是爭執的時候！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"왜!","JPN":"なによ！？","ENG":"Why not?","TWN":"為什麼？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"왜 그러시죠?","JPN":"どうしました？","ENG":"What’s wrong?","TWN":"什麼意思？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"댄스 배틀, 아무래도 못 참가할 것 같슴다.","JPN":"ダンスバトル、どうも参加できそうにないっす。","ENG":"I don’t think we’ll be attending the dance battle.","TWN":"可能無法參加舞蹈對決了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"응? 갑자기 왜?","JPN":"え？　急になんで？","ENG":"Why did you suddenly change your mind?","TWN":"嗯？怎麼突然這麼說？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"사람들이 빠져나가고 있네요. 무슨 일일까요?","JPN":"人々が会場から出てきていますね。どういうことでしょう？","ENG":"People are leaving. What’s going on here?","TWN":"因為人都走光啦，不知道發生什麼事？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L16_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"저 앞에를 보십셔!","JPN":"向こうをみてくださいっす！","ENG":"Look ahead!","TWN":"你們看前面！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"앞에?","JPN":"向こう？","ENG":"Ahead?","TWN":"前面？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네!","JPN":"モネ！","ENG":"Mone!","TWN":"莫妮！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네네~","JPN":"モネネ～","ENG":"Monene.","TWN":"莫妮妮～"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네! 모네!","JPN":"モネ！　モネ！","ENG":"Mone! Mone!","TWN":"莫妮！莫妮！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"펭귄들이잖아? 쟤네 아직도 여기 있어?","JPN":"ペンギンたちじゃない？　あの子たちまだここにいたの？","ENG":"Penguins! I didn’t know they were still here.","TWN":"企鵝？他們怎麼還在這裡？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"왕창 밀려온 뒤로 우리 마을에 아예 자리 잡았지 말임다.","JPN":"どっと押し寄せてきた後、うちの村に完全に定着したっす。","ENG":"They are now our village residents, since they’ve multiplied.","TWN":"他們到此一遊後，就乾脆在我們村裡住下來了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"맞아. 그리고는 우리 마을 명물이 됐단다.","JPN":"そう。そしてうちの村の名物になったのよ。","ENG":"Yes, and now they are also our village’s main attraction.","TWN":"沒錯，然後孩成爲村裡的吉祥物。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"엄니! 여긴 무슨 일임까?!","JPN":"母ちゃん！　どうしたっすか？","ENG":"Mama, what brought you here?","TWN":"媽媽！你怎麼會來這裡？！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"우리 모네가 친구들이랑 잘 놀고 있나 보러 왔지.","JPN":"モネが友達と仲良く遊んでいるか見に来たのよ。","ENG":"I came to see if you’re having a good time with your friends.","TWN":"我來看看莫妮和朋友們玩得開不開心。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"그런데 펭귄은 왜?","JPN":"ところでペンギンはどうしたの？","ENG":"Why were you talking about the penguins?","TWN":"不過，企鵝怎麼會？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"댄스 배틀 참가하려고 했는데, 사람들이 전부 펭귄에 정신 팔려 가 버렸슴다.","JPN":"ダンスバトルに参加しようとしたら、みんなペンギンに気を取られてしまったっす。","ENG":"We were planning to join the dance battle, but people left the show to see the penguins.","TWN":"本來想參加舞蹈對決的，可是大家都只顧著看企鵝。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"댄스 배틀은 어쩔 수 없이 다음 기회로 미뤄야겠어요.","JPN":"仕方ないですし、ダンスバトルは次の機会にしましょう。","ENG":"Too bad we won’t be participating in the dance battle.","TWN":"舞蹈對決只好等到下次囉。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"그래. 어쩔 수 없이.","JPN":"そうだね。仕方なく、ね。","ENG":"That is so sad.","TWN":"好，也只能這樣囉。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"그나저나 저 펭귄들이 명물이 됐다는 건 무슨 소리야?","JPN":"ところであのペンギンたちが名物になったっていうのはどういうこと？","ENG":"By the way, what do you mean that the penguins became the main attraction?","TWN":"話說回來，那些企鵝成爲吉祥物是什麼意思？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"며칠 전에 넷튜브에 올린 동영상 덕분이란다. 다들 펭귄들에 대해 알고 있던걸.","JPN":"数日前にネットチューブにアップした動画のおかげなのよ。みんなペンギンについて知っているわ。","ENG":"Thanks to the video that was uploaded on NetTube, everyone knows about the penguins.","TWN":"因為前幾天上傳到社群平台的影片，大家發現這裡有企鹅。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"누굴 닮았는지 꽤 귀엽고 말이야. 후훗.","JPN":"誰に似たのか、結構可愛いしね。フフッ。","ENG":"And they’re very cute, just like someone they resemble.","TWN":"也不知道像誰，長得那摩可愛，呵呵～"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"헤헷. 괜히 쑥스럽지 말임다~","JPN":"ヘヘッ、ちょっと照れてしまうっす。","ENG":"Heh heh. You’re making me blush, mama.","TWN":"嘿嘿，有點害羞呢～"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"그럼 잘된 거네. 마을에 사람이 안 와서 고민이었잖아.","JPN":"ならよかったじゃない。村に観光客が来なくて悩んでいたでしょ。","ENG":"Well, good for you. You were worried that tourists weren’t coming to your village.","TWN":"很棒欸！原本不是還擔心沒人來嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"레알로 축하드립니다. 모네 어머니.","JPN":"オメオメです、モネのお母さん。","ENG":"I truly congratulate you.","TWN":"伯母，真替你們開心。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"고마워요. 그렇지만…….","JPN":"ありがとうございます。でも……","ENG":"Thank you. But...","TWN":"謝謝。可是…"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"?!","JPN":"！？","ENG":"?!","TWN":"？！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_CARTOON_03"},{"id":"L6_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"?? 이게 무슨 소리죠?","JPN":"？？　これは何の音ですか？","ENG":"?? What was that?","TWN":"？？這是什麼聲音？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네에?","JPN":"モネエ？","ENG":"Monee?","TWN":"莫妮妮？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"저김다! 펭귄 모네가 갑자기 펑! 하고 사라졌슴다!!","JPN":"あそこっす！　ペンギンモネがいきなりポッと消えたっす。","ENG":"Look! A Mone Penguin just disappeared!","TWN":"就是那樣！企鵝莫妮會突然砰地一聲就消失不見！！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"바닥에 뭐가 떨어져 있는데?","JPN":"地面に何か落ちてるよ？","ENG":"And there’s something left on the ground.","TWN":"好像有東西掉下來？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"펭귄 인형옷이로군요. 본체는 모네 말대로 사라진 것 같아요.","JPN":"ペンギンの着ぐるみです。本体はモネの言うとおり消えたみたいです。","ENG":"A penguin costume. It looks like the penguin itself is gone.","TWN":"是企鵝娃娃裝。就像莫妮說的，主體好像消失了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"……이런 식으로 사라져서 문제란다.","JPN":"……こんなふうに消えてしまうから問題なのよ。","ENG":"... The penguins have been disappearing like that.","TWN":"…問題就是企鵝會像這樣突然消失。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"그 론 리란 여자가 만들었다며? 이럴 때 어딜 간 거래?","JPN":"あのローン・リーという女が作ったんでしょう？　こんな時にどこに行ったの？","ENG":"They were made by Lone Lee, where is she?","TWN":"聽說是那個叫隆利的女生做的？這時候她跑哪去啦？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"수배자라는 입장 때문에 숨어 있지 않을까요?","JPN":"手配されているから、隠れているんじゃないでしょうか。","ENG":"She’s a prison escapee, so I think she’s in hiding.","TWN":"會不會因爲她是通緝犯，所以躲起來啦？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"그럼 이 펭귄들은 더 안 나타난다는 거야?","JPN":"それじゃあこのペンギンたちはもう現れないってこと？","ENG":"And you’re not getting any more penguins?","TWN":"所以這些企鵝消失後就不會再出現嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"그래서 고민이란다. 펭귄들이 사라지면 다들 아쉬워할 거야.","JPN":"だから悩んでいるのよ。ペンギンたちがいなくなったらみんな寂しがるわ。","ENG":"That’s the problem. When they’re all gone, people will be disappointed.","TWN":"所以說很苦惱。因為企鵝消失的話，大家都會很捨不得的。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"적어도 오늘 오신 분들이라도 즐겁게 지내다 가시면 좋을 텐데…….","JPN":"少なくとも今日いらっしゃった方には楽しく過ごしてもらいたいけど……","ENG":"Well, I hope people enjoy themselves for today, at least.","TWN":"希望至少今天來到這裡的人可以盡興……"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"엄니! 걱정 마십셔!!","JPN":"母ちゃん！　心配しないでっす！！","ENG":"Mama! Don’t worry about it!","TWN":"媽媽！請不用擔心唷！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"울 엄니 고민은 모네가 해결해줄 검다!","JPN":"母ちゃんの悩みはモネが解決してあげるっす！","ENG":"Mone will solve your troubles!","TWN":"媽媽的煩惱由我來解決唷！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"그러니까…… 그러니까아……","JPN":"だから……だから……","ENG":"So... so...","TWN":"那個…那個…"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"이 인형옷을 모네가 입는 검다!","JPN":"この着ぐるみをモネが着るっす！","ENG":"I’ll be wearing this penguin costume!","TWN":"我來穿這件娃娃裝吧！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L32_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"얘가 또……","JPN":"そんな……","ENG":"Oh, no...","TWN":"這孩子又…"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"유감스럽겠지만, 모네한테 맞는 크기는 아닙니다.","JPN":"残念ながら、モネが入りそうなサイズではないです。","ENG":"Unfortunately, it doesn’t fit you.","TWN":"可惜，這不是莫妮的尺寸。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"별로 상관없긴 한데, 그럼 너 저거 입고 계속 여기 있을 생각이야?","JPN":"それは別にいいけど、あんたあれを着てずっとここで暮らす予定なの？","ENG":"I don’t really care, but are you planning to stay here with the costume?","TWN":"我是沒差啦，但你是想穿著那身娃娃裝繼續待在這裡嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"아차! 메이드 일을 깜빡했슴다!","JPN":"しまった！　メイドの仕事をうっかりしてたっす！","ENG":"Oh! I almost forgot that I was a maid, ma’am!","TWN":"哎呀！差點忘記女僕長交代的事！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L41_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"그럴 필요 없이 내가 요리를 할 테니까 그걸 넣어 보면 어때?","JPN":"じゃあ、私が料理をするから、アレに入れてみたらどう？","ENG":"Better yet, how about using something that I cook?","TWN":"不用這麼麻煩，還是我來做料理，然後把料理放進去如何？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"어차피 초콜릿이었으니까 비슷하게 움직이지 않을까?","JPN":"どうせ元はチョコレートだったんだし、似たような感じで動くんじゃない？","ENG":"They were made of chocolate anyways, so my cooking must work the same, right?","TWN":"反正都是巧克力，應該差不多吧？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"그렇게 해서 무슨 괴물을 만들 생각이죠, 리코리스?","JPN":"それで何の怪物を作り出すつもりですか、リコリス？","ENG":"What kind of monster are you planning to create, Lycoris?","TWN":"你想製造出什麼樣的怪物，莉克麗絲？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"불타는 칠리 소스를 뿜고 다니는 괴물 새?","JPN":"燃えるチリソースを吹きかける怪鳥？","ENG":"A monster bird fuming with fiery chili sauce?","TWN":"噴著火辣辣椒醬的怪物鳥？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"절대 그럴 리 없거든?!","JPN":"絶対そんなことないからね！","ENG":"That’s not going to happen!","TWN":"你想太多？！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"그래도 초콜릿을 대신할 걸 채워 넣자는 생각은 좋은 아이디어 같네.","JPN":"でも、チョコレートの代わりになるものを入れようという考えはいいアイデアだと思うわ。","ENG":"Well, filling them up with something other than chocolate does sound like a good idea though.","TWN":"不過放入可以代替巧克力的東西，這個想法不錯。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L49_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"초콜릿이라서 그렇게 귀여운 아이들이었으려나? 미트 파이는 어떨까?","JPN":"中身がチョコレートだったからあんなに可愛らしい子たちができたのかしら。ミートパイはどう？","ENG":"Maybe they were sweet little things because they were made of chocolate. How about we try meat pies?","TWN":"難道因爲是巧克力才那麼可愛嗎？放肉餅會怎麼樣？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L50_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"모네는 찬성임다! 왠지 재밌을 거 같지 말임다!","JPN":"モネは賛成っす！　なんか面白そうっす！","ENG":"Mone concurs! I think it’s going to be fun, mama!","TWN":"莫妮贊成！感覺會很有趣唷！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"그러면 각자 요리를 하나씩 해 와서 인형옷에 넣어 보자.","JPN":"それじゃあ、それぞれ料理を1つずつ用意して着ぐるみに入れてみましょう。","ENG":"How about each of us cook a dish and put it in the penguin costume?","TWN":"那就各自做一道菜，放進娃娃裝裡看看吧！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"어때? 그렇게 해줄 수 있겠니?","JPN":"どう？　できそうかしら？","ENG":"What do you say? Can you do that?","TWN":"如何？你可以嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"넵, 엄니! 모네도 끝내 주는 요리를 만들어 오겠슴다!","JPN":"はい、母ちゃん！　モネもとびっきりおいしい料理を作ってくるっす！","ENG":"Yes, mama! Mone will make the best dish ever!","TWN":"嗯，媽媽！莫妮會做出絕佳的料理唷！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"내가 바로 요리 담당 메이드라고. 한수 가르쳐 주지.","JPN":"私は料理担当のメイドなの。格の違いを見せてやるわ。","ENG":"I’m a maid in charge of the kitchen. Let me show you what I can do.","TWN":"我就是負責料理的女僕，我教你一招吧。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"오키도키입니다. 모네 어머니.","JPN":"りょ、です。","ENG":"Okely dokely, ma’am.","TWN":"OK喔，伯母。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"자, 그러면 첫 번째 요리는 리코리스구나?","JPN":"さて、最初の料理はリコリスさんのね！","ENG":"So, the first dish is from Lycoris.","TWN":"第一道料理是莉克麗絲的嗎？"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"힘내십셔, 선배님!","JPN":"頑張れっす、先輩！","ENG":"I’m rooting for you, ma’am!","TWN":"加油唷，前輩！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"흥, 이번에 만든 칠리 도그는 기대해도 좋을걸.","JPN":"ふん、今回作ったチリドッグは期待してもいいわよ。","ENG":"Well, you can look forward to my chili dog.","TWN":"哼，敬請期待這次做的辣醬熱狗吧！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"다들 뭐라고 해서 새콤한 맛만 나게 만들었거든.","JPN":"みんな味に文句が多いから、甘酸っぱい味にしてみたの。","ENG":"I made it sweet and sour this time, since you were all scolding me for making food too spicy.","TWN":"大家對辣好像很有意見，所以我這次做成酸的。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"자, 이걸 이렇게 넣으면…….","JPN":"さあ、これをこうすれば……","ENG":"Now, let’s pour it into the costume...","TWN":"好，把這個放進去……"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TONFAICE_PENGUIN_NULL_NULL","text":{"KOREA":"모네!!","JPN":"モネ！！","ENG":"Mone!!","TWN":"莫妮！！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFAICE_PENGUIN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_CARTOON_03"},{"id":"L21_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"오오! 정말 다시 펭귄이 움직이지 말임다!","JPN":"おお！　本当にペンギンが動き始めたっす！","ENG":"Ooh! The penguin is moving again!","TWN":"哦哦！企鵝真的又動咧！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"그런데 저 아이……. 묘하게 화난 것 같지 않니?","JPN":"でもあの子……妙に怒っている気がしない？","ENG":"But this penguin... looks somewhat angry.","TWN":"但是……你不覺得那隻企鵝好像在生氣嗎？"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"TONFAICE_PENGUIN_NULL_NULL","text":{"KOREA":"모네! 모네! 모오네!","JPN":"モネ！　モネ！　モォネ！","ENG":"Mone! Mone! Mo-o-ne!","TWN":"莫妮！莫妮！莫妮！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFAICE_PENGUIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"다, 다시 인형옷으로 돌아가 버렸네?","JPN":"ま、また着ぐるみに戻っちゃった！？","ENG":"Sh-she’s gone again!","TWN":"又…又變成娃娃裝了？"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"리코리스의 무지성 매운 맛 음식은 못 참아서 그렇겠죠.","JPN":"リコリスの激辛料理に腹を立てたのでしょう。","ENG":"She probably couldn’t stand your insanely spicy food.","TWN":"因爲無法忍受莉克麗絲的極辣料理吧？"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"그러면 다음은 제 감자 수프 차례군요.","JPN":"それでは、次は私のジャガイモスープの番ですね。","ENG":"It’s my turn now. I brought some potato soup.","TWN":"那接下來輪到我的馬鈴薯湯囉。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"TONFAICE_PENGUIN_NULL_NULL","text":{"KOREA":"모네……?","JPN":"モネ……？","ENG":"Mone...","TWN":"莫妮…？"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFAICE_PENGUIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_CARTOON_03"},{"id":"L32_1","type":"dialog","speaker":"TONFAICE_PENGUIN_NULL_NULL","text":{"KOREA":"모네네……?","JPN":"モネネ……？","ENG":"Monene...","TWN":"莫妮妮…？"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFAICE_PENGUIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"묘하게 기운이 없어 보이지 말임다……?","JPN":"妙に元気がなさそうに見えるっす……？","ENG":"She looks very... sluggish, ma’am.","TWN":"感覺好像有氣無力的樣子唷…？"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"그러게. 굉장히 졸린 것 같아.","JPN":"そうね。すごくだるそうにしてるわね。","ENG":"Yeah, I think she’s sleepy.","TWN":"對啊，看起來很愛睏的樣子。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"TONFAICE_PENGUIN_NULL_NULL","text":{"KOREA":"모네네에…….","JPN":"モネネエ……","ENG":"Moneneee...","TWN":"莫莫妮妮…"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFAICE_PENGUIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"그대로 잠들어 버렸네. 대체 수프에 뭘 넣은 거야?","JPN":"そのまま寝ちゃった。スープにいったい何を入れたの？","ENG":"She fell asleep. What did you put into that soup?","TWN":"就這樣睡着咧！你到底在湯裡放了什麼？"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L43_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"별거 아닙니다. 숙면을 위해 아로마 향이 나는 즉효성 수면제를 좀 넣었어요.","JPN":"特別なものは入れていません。熟眠のためにアロマの香りがする即効性睡眠薬をちょっとだけ足しました。","ENG":"Nothing special. An aromatic sleeping pill for comfortable sleep.","TWN":"沒什麼，就是能夠立刻入眠的精油香氛速效安眠藥。 "},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"사람 먹는 거에 그딴 걸 넣으면 어떡해?!","JPN":"食べ物にそんなのを入れちゃダメでしょ！","ENG":"Why would you put a sleeping pill in the soup?","TWN":"人吃東西怎麼可以放那種東西？！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"두 사람 다 정성은 알겠지만, 이대로는 조금 어렵겠구나.","JPN":"二人とも気持ちは伝わるけど、このままだと厳しそうだわ。","ENG":"Thank you for trying, both of you. But I don’t think your methods are working out.","TWN":"我很感謝你們兩個的好意，但這樣下去事情好像會有點困難。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L48_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"엄니! 아직 모네가 만든 빙수가 남았지 말임다!","JPN":"母ちゃん！　まだモネが作ったかき氷が残ってるっす！","ENG":"Mama! Mone brought a bowl of shaved ice!","TWN":"媽媽！還有莫妮做的刨冰唷！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"빙수……? 이거 그냥 얼음 가루 아냐?","JPN":"かき氷……？　ただの氷の粉じゃない？","ENG":"Shaved ice? But I see nothing but crushed ice.","TWN":"刨冰…？這不是普通的碎冰嗎？"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"제 눈에도 그렇게 보여요. 소스나 다른 재료는 눈 씻고 찾아봐도 없습니다.","JPN":"私にもそう見えます。シロップや他の材料は、いくら目をこすって見てもありません。","ENG":"Yes. I don’t see any other ingredients. No sweet condiments or syrups.","TWN":"我也沒看到果醬或其他的配料。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"모네. 우리는 이런 걸 얼음이라 부르기로 약속했어요.","JPN":"モネ、世間一般ではこういうものはそのまま氷と呼んでいますよ。","ENG":"Mone. I believe there is a social convention in which people call this “ice”.","TWN":"莫妮，通常我們將這個稱之為碎冰。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"아님다! 모네네 아부지는 이렇게 드시지 말임다!","JPN":"違うっす！　モネの父ちゃんはいつもこれで食べているっす！","ENG":"No, ma’am! This is how Mone’s papa enjoys shaved ice!","TWN":"不是的！莫妮的爸爸都是這樣吃的！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"이걸 넣으면 아부지처럼 엄청 힘 센 펭귄이 될 검다!","JPN":"これを入れれば、父ちゃんみたいに力持ちのペンギンになると思うっす！","ENG":"I’m sure it will give strength to the penguins, just like my papa!","TWN":"把這個放進去的話，就會變成像爸爸一樣的大力士企鵝唷！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TONFAICE_PENGUIN_NULL_NULL","text":{"KOREA":"모네.","JPN":"モネ。","ENG":"Mone.","TWN":"莫妮。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFAICE_PENGUIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"어째……. 표정이 좀 다른 것 같다?","JPN":"なんだか……表情がちょっと違う？","ENG":"Oh? She looks a bit... different.","TWN":"怎麼……表情好像有點不太對勁？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"그렇네요. 얼음을 잔뜩 넣었다고 화가 난 걸까요?","JPN":"そうですね。氷詰めにされて怒ったのでしょうか？","ENG":"Yeah. Is she mad about having too much ice?","TWN":"對啊，是因爲放太多冰塊不高興嗎？"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"TONFAICE_PENGUIN_NULL_NULL","text":{"KOREA":"모네.","JPN":"モネ。","ENG":"Mone.","TWN":"莫妮。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFAICE_PENGUIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TONFAICE_PENGUIN_NULL_NULL","text":{"KOREA":"모네네.","JPN":"モネネ。","ENG":"Monene.","TWN":"莫妮妮。"},"stage":{"bg":"VILLAGE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFAICE_PENGUIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"앗, 친구들이 잔뜩 나타났지 말임다!","JPN":"あっ、仲間がいっぱい現れたっす！","ENG":"Oh, her friends are here!","TWN":"哇，出現好多隻！"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"이쪽으로 달려듭니다! 대비하세요!","JPN":"こちらにむかってきます！　備えてください！","ENG":"They are coming this way! Embrace yourselves!","TWN":"向這邊衝過來囉！請做好準備！"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"기껏 해변까지 와 놓고 이게 무슨 고생이야, 진짜?!","JPN":"せっかくビーチに来たのに、なんなのこのシチュエーションは？　もおー！","ENG":"Oh, why should I suffer like this?","TWN":"好不容易來到海邊，我怎麼這麼命苦，真是的？！"},"stage":{"bg":"VILLAGE2","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};